cat <<'EOF' > csv-parser.ts
export type CSVRow = Record<string, unknown>;

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number | null;
  count(): number;
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

class CSVResultImpl implements CSVResult {
  constructor(
    public readonly rows: CSVRow[],
    public readonly headers: string[],
    public readonly errors: CSVError[]
  ) {}

  filter(predicate: (row: CSVRow) => boolean): CSVResult {
    const filtered = this.rows.filter(predicate);
    return new CSVResultImpl(filtered, this.headers, this.errors);
  }

  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number' && Number.isFinite(value)) {
        return acc + value;
      }
      return acc;
    }, 0);
  }

  average(column: string): number | null {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number' && Number.isFinite(value)) {
        total += value;
        count += 1;
      }
    }
    if (count === 0) {
      return null;
    }
    return total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<unknown, CSVRow[]> {
    const map = new Map<unknown, CSVRow[]>();
    for (const row of this.rows) {
      const key = row[column];
      const bucket = map.get(key);
      if (bucket) {
        bucket.push(row);
      } else {
        map.set(key, [row]);
      }
    }
    return map;
  }
}

const numberRegex = /^[+-]?(?:\d+\.\d*|\d*\.\d+|\d+)$/;

function coerceValue(value: string): unknown {
  const trimmed = value.trim();
  if (trimmed === '' || trimmed.toLowerCase() === 'null') {
    return null;
  }
  if (/^(true|false)$/i.test(trimmed)) {
    return trimmed.toLowerCase() === 'true';
  }
  if (numberRegex.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num) && Number.isFinite(num)) {
      return num;
    }
  }
  return value;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator =
    options.lineSeparator && options.lineSeparator.length > 0
      ? options.lineSeparator
      : '\n';

  const rawRows: string[][] = [];
  const rowLineNumbers: number[] = [];

  let currentRowFields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let currentRowNumber = 1;

  const pushField = () => {
    currentRowFields.push(currentField);
    currentField = '';
  };

  const pushRow = () => {
    rawRows.push(currentRowFields);
    rowLineNumbers.push(currentRowNumber);
    currentRowNumber += 1;
    currentRowFields = [];
  };

  const matchLineSeparator = (index: number): boolean => {
    if (!lineSeparator) {
      return false;
    }
    return input.slice(index, index + lineSeparator.length) === lineSeparator;
  };

  for (let i = 0; i < input.length; i++) {
    const char = input[i];

    if (char === quote) {
      if (inQuotes) {
        if (input[i + 1] === quote) {
          currentField += quote;
          i += 1;
          continue;
        }
        inQuotes = false;
        continue;
      }
      inQuotes = true;
      continue;
    }

    if (!inQuotes && matchLineSeparator(i)) {
      pushField();
      pushRow();
      i += lineSeparator.length - 1;
      continue;
    }

    if (!inQuotes && char === delimiter) {
      pushField();
      continue;
    }

    currentField += char;
  }

  const errors: CSVError[] = [];

  if (inQuotes) {
    errors.push({
      row: currentRowNumber,
      message: 'Unterminated quoted field detected at end of input',
    });
  } else if (currentField !== '' || currentRowFields.length > 0) {
    pushField();
    pushRow();
  }

  if (rawRows.length === 0) {
    return new CSVResultImpl([], [], errors);
  }

  const headers = rawRows[0];
  const parsedRows: CSVRow[] = [];

  for (let i = 1; i < rawRows.length; i++) {
    const row = rawRows[i];
    const rowNumber = rowLineNumbers[i];
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} columns but got ${row.length}`,
      });
      continue;
    }
    const record: CSVRow = {};
    for (let j = 0; j < headers.length; j++) {
      record[headers[j]] = coerceValue(row[j]);
    }
    parsedRows.push(record);
  }

  return new CSVResultImpl(parsedRows, headers, errors);
}
