  const typeCSV = 'int,float,boolTrue,boolFalse,nullValue,stringValue,empty\n42,3.5,TRUE,false,NULL,hello,';
  const typeResult = parseCSV(typeCSV);
  const [typeRow] = typeResult.rows;
  assert(typeRow.int === 42, 'integer values should be coerced');
  assert(typeRow.float === 3.5, 'float values should be coerced');
  assert(typeRow.boolTrue === true && typeRow.boolFalse === false, 'booleans should be case-insensitive');
  assert(typeRow.nullValue === null, 'null literal should result in null');
  assert(typeRow.stringValue === 'hello', 'unmatched values should remain strings');
  assert(typeRow.empty === null, 'empty strings should become null');

  // Malformed rows do not crash parser
  const malformedCSV = 'id,name\n1,Alice\n2\n3,Bob,Extra';
  const malformedResult = parseCSV(malformedCSV);
  assert(
    malformedResult.errors.length === 2,
    'should collect errors for rows that do not match header length'
  );
  assertDeepEqual(
    malformedResult.errors.map((error) => error.row),
    [3, 4],
    'errors should report the correct row numbers'
  );
  assert(malformedResult.rows.length === 1, 'malformed rows should be skipped');

  // Filtering
  const filterCSV = 'name,age\nAlice,30\nBob,20\nClara,40';
  const filterResult = parseCSV(filterCSV);
  const filtered = filterResult.filter((row) => typeof row.age === 'number' && row.age >= 30);
  assert(filtered.rows.length === 2, 'filter should reduce matching rows');
  assert(filtered.rows.every((row) => (row.age as number) >= 30), 'filtered rows should satisfy predicate');

  // Aggregation functions
  const statsCSV = 'category,value\nA,10\nB,20\nA,30\nA,notnum\nB,5';
  const stats = parseCSV(statsCSV);
  assert(stats.sum('value') === 65, 'sum should accumulate numeric values only');
  assert(stats.average('value') === 16.25, 'average should be based on numeric values');
  assert(stats.count() === 5, 'count should return number of parsed rows');
  const groups = stats.groupBy('category');
  assert(groups.get('A')?.length === 3, 'groupBy should group rows with matching values');
  assert(groups.get('B')?.length === 2, 'groupBy should create distinct buckets');
  const numericOnly = parseCSV('value\nfoo');
  assert(numericOnly.average('value') === null, 'average should return null when no numeric values');

  // Edge cases
  const empty = parseCSV('');
  assert(empty.headers.length === 0 && empty.rows.length === 0, 'empty input should result in empty structures');
  assert(empty.count() === 0, 'count should be zero for empty CSV');

  const singleColumn = parseCSV('label\nonly');
  assert(singleColumn.headers.length === 1, 'should handle single-column input');
  assert(singleColumn.rows[0].label === 'only', 'single-value rows should parse correctly');

  const singleRow = parseCSV('col1,col2\none,1');
  assert(singleRow.rows.length === 1, 'should handle single-row input');

  const bigField = parseCSV(`payload\n${'x'.repeat(10000)}`);
  assert(
    typeof bigField.rows[0].payload === 'string' && bigField.rows[0].payload === 'x'.repeat(10000),
    'should support very large fields'
  );

  console.log('All csv-parser tests passed.');
